DROP TABLE IF EXISTS data_admin;
CREATE TABLE `data_admin` (
  `id_admin` varchar(50) DEFAULT NULL,
  `nama` varchar(100) DEFAULT NULL,
  `username` varchar(50) DEFAULT NULL,
  `password` varchar(100) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;
DROP TABLE IF EXISTS data_grafik_sensor;
CREATE TABLE `data_grafik_sensor` (
  `id_grafik_sensor` varchar(50) NOT NULL,
  `id_project` varchar(50) DEFAULT NULL,
  `id_sensor_project` varchar(50) DEFAULT NULL,
  `id_jenis_grafik` varchar(50) DEFAULT NULL,
  `perintah` tinytext DEFAULT NULL,
  PRIMARY KEY (`id_grafik_sensor`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;
DROP TABLE IF EXISTS data_input;
CREATE TABLE `data_input` (
  `id_input` varchar(50) DEFAULT NULL,
  `id_project` varchar(50) DEFAULT NULL,
  `id_sensor_project` varchar(50) DEFAULT NULL,
  `waktu` datetime DEFAULT NULL,
  `nilai` tinytext DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;
DROP TABLE IF EXISTS data_jadwal;
CREATE TABLE `data_jadwal` (
  `id_jadwal` varchar(50) NOT NULL,
  `id_project` varchar(50) NOT NULL,
  `waktu` time NOT NULL,
  `id_respon` varchar(50) NOT NULL,
  `judul` varchar(500) NOT NULL,
  `status` enum('aktif','tidak_aktfi') NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_unicode_ci;
DROP TABLE IF EXISTS data_jenis_grafik;
CREATE TABLE `data_jenis_grafik` (
  `id_jenis_grafik` varchar(50) DEFAULT NULL,
  `jenis_grafik` varchar(250) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;
DROP TABLE IF EXISTS data_notif;
CREATE TABLE `data_notif` (
  `id_notif` varchar(50) NOT NULL,
  `kategori` enum('telegram','whatsapp','email','alert') NOT NULL,
  `id_project` varchar(50) NOT NULL,
  `target` varchar(100) NOT NULL,
  `source` varchar(250) NOT NULL,
  `config` varchar(250) NOT NULL,
  `prefix_triger` varchar(100) NOT NULL,
  `operator_triger` enum('=','<','>','!=') NOT NULL,
  `value_triger` varchar(100) NOT NULL,
  `text` text NOT NULL,
  PRIMARY KEY (`id_notif`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_unicode_ci;
DROP TABLE IF EXISTS data_notif_history;
CREATE TABLE `data_notif_history` (
  `id_notif_history` varchar(50) NOT NULL,
  `id_project` varchar(50) NOT NULL,
  `waktu` datetime NOT NULL,
  `id_notif` varchar(100) NOT NULL,
  `informasi` varchar(100) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_unicode_ci;
DROP TABLE IF EXISTS data_output;
CREATE TABLE `data_output` (
  `id_output` varchar(50) NOT NULL,
  `id_project` varchar(50) DEFAULT NULL,
  `nama` varchar(250) DEFAULT NULL,
  `nilai` varchar(100) DEFAULT NULL,
  PRIMARY KEY (`id_output`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;
DROP TABLE IF EXISTS data_project;
CREATE TABLE `data_project` (
  `id_project` varchar(50) NOT NULL,
  `nama_project` varchar(250) DEFAULT NULL,
  `waktu` datetime DEFAULT NULL,
  `id_user` varchar(50) DEFAULT NULL,
  `board` varchar(250) DEFAULT NULL,
  `lat` varchar(250) DEFAULT NULL,
  `lng` varchar(250) DEFAULT NULL,
  `nama_lokasi` varchar(250) DEFAULT NULL,
  `apikey` varchar(250) DEFAULT NULL,
  `status` enum('aktif','tidak aktif') DEFAULT NULL,
  PRIMARY KEY (`id_project`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;
DROP TABLE IF EXISTS data_respon;
