DROP TABLE IF EXISTS data_sensor;
CREATE TABLE `data_sensor` (
  `id_sensor` varchar(50) DEFAULT NULL,
  `nama_sensor` varchar(250) DEFAULT NULL,
  `gambar` varchar(250) DEFAULT NULL,
  `satuan` varchar(50) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;
DROP TABLE IF EXISTS data_sensor_project;
CREATE TABLE `data_sensor_project` (
  `id_sensor_project` varchar(50) NOT NULL,
  `id_project` varchar(50) DEFAULT NULL,
  `id_sensor` varchar(50) DEFAULT NULL,
  `prefix` varchar(150) DEFAULT NULL,
  `status` enum('aktif','tidak aktif') DEFAULT NULL,
  PRIMARY KEY (`id_sensor_project`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;
DROP TABLE IF EXISTS data_user;
CREATE TABLE `data_user` (
  `id_user` varchar(50) DEFAULT NULL,
  `nama_user` varchar(100) NOT NULL,
  `waktu` datetime NOT NULL,
  `alamat` varchar(100) NOT NULL,
  `pekerjaan` varchar(100) NOT NULL,
  `no_telepon` varchar(100) NOT NULL,
  `email` varchar(100) NOT NULL,
  `username` varchar(50) DEFAULT NULL,
  `password` varchar(250) NOT NULL,
  PRIMARY KEY (`password`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;
